/* src/cmd_handler.c */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void handle_command(void) {
    char buf[256];
    const char *cmd = getenv("USER_CMD");
    if (cmd == NULL) {
        return;
    }
    /* vulnerable: no sanitization of environment variable */
    snprintf(buf, sizeof(buf), "/bin/sh -c '%s'", cmd);
    system(buf);  /* line 42: CWE-78 OS command injection */
}

/* src/main.c */
#include <stdio.h>
extern void handle_command(void);

int main(int argc, char *argv[]) {
    printf("Processing command...\n");
    handle_command();
    return 0;
}
